#include "mpu9250.h"
#include <Wire.h>
#include <MPU9250.h>
static MPU9250 imu(Wire,0x68);
static float _ax=0,_ay=0,_az=0,_gx=0,_gy=0,_gz=0,_mx=0,_my=0,_mz=0;static unsigned long _l=0;
void mpu9250_setup(){Wire.begin();if(imu.begin()<0){Serial.println("[mpu9250] Fail!");return;}Serial.println("[mpu9250] OK 9DOF");}
void mpu9250_loop(){if(millis()-_l<50)return;_l=millis();imu.readSensor();_ax=imu.getAccelX_mss();_ay=imu.getAccelY_mss();_az=imu.getAccelZ_mss();_gx=imu.getGyroX_rads();_gy=imu.getGyroY_rads();_gz=imu.getGyroZ_rads();_mx=imu.getMagX_uT();_my=imu.getMagY_uT();_mz=imu.getMagZ_uT();}
float mpu9250_accel_x(){return _ax;}
float mpu9250_accel_y(){return _ay;}
float mpu9250_accel_z(){return _az;}
float mpu9250_gyro_x(){return _gx;}
float mpu9250_gyro_y(){return _gy;}
float mpu9250_gyro_z(){return _gz;}
float mpu9250_mag_x(){return _mx;}
float mpu9250_mag_y(){return _my;}
float mpu9250_mag_z(){return _mz;}
